    // ── test_spirv_header ─────────────────────────────────────────────────────

    #[test]
    fn test_spirv_header() {
        let glsl = convert_mlir_to_spirv(load_store_mlir()).unwrap();
        assert!(glsl.contains("#version 450"), "missing #version 450");
        assert!(
            glsl.contains("layout(local_size_x"),
            "missing local_size_x layout"
        );
        assert!(
            glsl.contains("layout(push_constant)"),
            "missing push_constant"
        );
        assert!(
            glsl.contains("void main()"),
            "missing void main()"
        );
        // Should NOT have subgroup extensions for a copy kernel
        assert!(
            !glsl.contains("GL_KHR_shader_subgroup"),
            "unexpected subgroup extension in copy kernel"
        );
    }

    // ── test_spirv_softmax ────────────────────────────────────────────────────

    #[test]
    fn test_spirv_softmax() {
        let glsl = convert_mlir_to_spirv(softmax_mlir()).unwrap();
        assert!(
            glsl.contains("GL_KHR_shader_subgroup_arithmetic"),
            "missing subgroup_arithmetic extension"
        );
        assert!(
            glsl.contains("GL_KHR_shader_subgroup_basic"),
            "missing subgroup_basic extension"
        );
        assert!(glsl.contains("subgroupMax"), "missing subgroupMax");
        assert!(glsl.contains("subgroupAdd"), "missing subgroupAdd");
        assert!(glsl.contains("shared"), "missing shared memory declaration");
        assert!(glsl.contains("sdata"), "missing sdata shared array");
        // 5-step softmax: barrier appears twice (after max-subgroup and sum-subgroup)
        let barrier_count = glsl.matches("barrier();").count();
        assert!(
            barrier_count >= 2,
            "expected at least 2 barrier() calls, got {}",
            barrier_count
        );
        assert!(glsl.contains("exp(val - row_max)"), "missing exp step");
        assert!(glsl.contains("exp_val / row_sum"), "missing normalize step");
    }

    // ── test_spirv_add ────────────────────────────────────────────────────────

    #[test]
    fn test_spirv_add() {
        let glsl = convert_mlir_to_spirv(add_mlir()).unwrap();
        // Should have 3 buffer bindings (p0, p1, p2)
        assert!(
            glsl.contains("binding = 0"),
            "missing binding 0"
        );
        assert!(
            glsl.contains("binding = 1"),
            "missing binding 1"
        );
        assert!(
            glsl.contains("binding = 2"),
            "missing binding 2"
        );
        // Element-wise add
        assert!(
            glsl.contains("p0[gid] + p1[gid]"),
            "missing p0[gid] + p1[gid]"
        );
        assert!(
            glsl.contains("p2[gid]"),
            "missing output write to p2[gid]"
        );
        // No subgroup code needed
        assert!(
            !glsl.contains("subgroupMax"),
            "unexpected subgroupMax in add kernel"
        );
    }

    // ── test_spirv_exp ────────────────────────────────────────────────────────

    #[test]
    fn test_spirv_exp() {
        let glsl = convert_mlir_to_spirv(exp_mlir()).unwrap();
        assert!(
            glsl.contains("exp(p0[gid])"),
            "missing exp(p0[gid])"
        );
        assert!(
            glsl.contains("p1[gid]"),
            "missing output write to p1[gid]"
        );
        // Should only have 2 buffer bindings
        assert!(
            !glsl.contains("binding = 2"),
            "unexpected third buffer binding in exp kernel"
        );
    }

