    // ── test_spirv_silu_mul_fusion ──────────────────────────────────────────

    #[test]
    fn test_spirv_silu_mul_fusion() {
        // SiLU followed by Mul should fuse into a single SiLUMul kernel
        let mlir = r#"
module {
  llvm.func @gated_mlp(%arg0: !llvm.ptr<1>, %arg1: !llvm.ptr<1>, %arg2: !llvm.ptr<1>) attributes {hacc.entry} {
    ^bb0:
    %r = llvm.mlir.constant(1 : i32) : i32
    %c = llvm.mlir.constant(8960 : i32) : i32
    %gate = llvm.call @__tile_load_f32(%arg0, %r, %c) : (!llvm.ptr<1>, i32, i32) -> i32
    %up = llvm.call @__tile_load_f32(%arg1, %r, %c) : (!llvm.ptr<1>, i32, i32) -> i32
    %silu = llvm.call @__tile_silu_f32(%gate, %gate, %r, %c) : (i32, i32, i32, i32) -> i32
    %fused = llvm.call @__tile_mul_f32(%silu, %up, %r, %c) : (i32, i32, i32, i32) -> i32
    llvm.call @__tile_store_f32(%arg2, %fused, %r, %c) : (!llvm.ptr<1>, i32, i32, i32) -> ()
    llvm.return
  }
}
"#;
        let glsl = convert_mlir_to_spirv(mlir).unwrap();
        assert!(glsl.contains("void main()"), "missing main:\n{}", glsl);
        // Must be a fused kernel: silu + mul in one expression
        assert!(glsl.contains("exp(-v)"), "must have silu computation:\n{}", glsl);
        assert!(glsl.contains("* p1[gid]"), "must multiply with second input:\n{}", glsl);
        // Must have 3 buffers (gate, up, output)
        assert!(glsl.contains("p0"), "must have p0 (gate input):\n{}", glsl);
        assert!(glsl.contains("p1"), "must have p1 (up input):\n{}", glsl);
        assert!(glsl.contains("p2"), "must have p2 (output):\n{}", glsl);
    }

